// Process the API response
const response = $input.item.json;

if (response.success && response.data) {
  const data = response.data;
  const summary = {
    total_leads: data.total_leads,
    overdue_count: data.overdue_count,
    due_today_count: data.due_today_count,
    due_this_week_count: data.due_this_week_count,
    leads: data.leads.map(lead => ({
      lead_id: lead.lead_id,
      contact_name: lead.contact_name,
      company_name: lead.company_name,
      priority_score: lead.priority_score,
      priority_label: lead.priority_label,
      next_followup_at: lead.next_followup_at,
      days_overdue: lead.days_overdue,
      next_action: lead.priority_label === 'Hot' || lead.priority_label === 'Overdue' ? 'Call immediately' : lead.priority_label === 'Warm' ? 'Send email' : 'Schedule follow-up'
    }))
  };

  return [{ json: summary }];
} else {
  return [{ json: { error: 'Failed to retrieve follow-ups', details: response } }];
}

// Generate a readable summary
const data = $input.item.json;

let summary = `Daily Follow-up Summary\n`;
summary += `========================\n`;
summary += `Total Leads: ${data.total_leads}\n`;
summary += `Overdue: ${data.overdue_count}\n`;
summary += `Due Today: ${data.due_today_count}\n`;
summary += `Due This Week: ${data.due_this_week_count}\n\n`;

if (data.leads && data.leads.length > 0) {
  summary += `Priority Leads:\n`;
  summary += `----------------\n`;

  data.leads.forEach((lead, index) => {
    const overdueStatus = lead.days_overdue > 0 ? `(${lead.days_overdue} days overdue)` : '';
    summary += `${index + 1}. ${lead.contact_name} - ${lead.company_name}\n`;
    summary += `   Priority: ${lead.priority_label} (${lead.priority_score})\n`;
    summary += `   Status: ${overdueStatus}\n`;
    summary += `   Action: ${lead.next_action}\n\n`;
  });
} else {
  summary += `No leads with follow-ups due.\n`;
}

return [{ json: { summary: summary, raw_data: data } }];
